from langflow.custom import Component
from langflow.io import MessageTextInput, Output
from langflow.schema import Data

from langchain_core.documents import Document

import fitz  # PyMuPDF
import os


class PDFPathToDocuments(Component):

    display_name = "PDF Path To Documents"

    description = (
        "Convert PDF from a file path into LangChain Documents with page metadata."
    )

    icon = "file-text"

    inputs = [
        MessageTextInput(
            name="pdf_path",
            display_name="PDF File Path",
            info="Enter the full path of the PDF file",
        ),
    ]

    outputs = [
        Output(
            display_name="Documents",
            name="documents",
            method="convert_pdf",
        ),
    ]

    def convert_pdf(self) -> Data:

        pdf_path = self.pdf_path

        # Check if path is empty
        if not pdf_path:
            return Data(
                value="No PDF path provided."
            )

        # Check if file exists
        if not os.path.exists(pdf_path):
            return Data(
                value=f"File not found: {pdf_path}"
            )

        # Check if file is a PDF
        if not pdf_path.lower().endswith(".pdf"):
            return Data(
                value="Provided file is not a PDF."
            )

        try:

            # Open PDF
            doc = fitz.open(pdf_path)

            documents = []

            total_pages = len(doc)

            # Process each page
            for page_num in range(total_pages):

                page = doc.load_page(page_num)

                text = page.get_text("text")

                # Skip empty pages
                if not text.strip():
                    continue

                # Create LangChain Document
                document = Document(

                    page_content=text,

                    metadata={
                        "page": page_num + 1,
                        "source": os.path.basename(pdf_path),
                        "full_path": pdf_path
                    }
                )

                documents.append(document)

            doc.close()

            return Data(
                value=documents
            )

        except Exception as e:

            return Data(
                value=f"Error processing PDF: {str(e)}"
            )
